// ── Validate & sanitise incoming ESP32 payload ──────────────────────────
const body = $input.first().json.body ?? $input.first().json;

const device_id   = String(body.device_id   ?? 'esp32-001');
const temperature = parseFloat(body.temperature ?? 0);
const voltage     = parseFloat(body.voltage     ?? 0);
const current     = parseFloat(body.current     ?? 0);
const gyro_x      = parseFloat(body.gyro_x      ?? 0);
const gyro_y      = parseFloat(body.gyro_y      ?? 0);
const gyro_z      = parseFloat(body.gyro_z      ?? 0);

// device_id format guard
if (!/^esp32-[a-zA-Z0-9\-]+$/.test(device_id)) {
  throw new Error(`Invalid device_id: ${device_id}`);
}

// numeric guard
if (isNaN(temperature) || isNaN(voltage) || isNaN(current)) {
  throw new Error('temperature / voltage / current must be numeric');
}

// Anomaly detection (defence-in-depth over ESP32 on-device check)
const reasons = [];
if (temperature >= 85)       reasons.push(`CRITICAL temperature (${temperature.toFixed(1)}C)`);
else if (temperature >= 70)  reasons.push(`High temperature (${temperature.toFixed(1)}C)`);
if (voltage < 3.0)           reasons.push(`Low voltage (${voltage.toFixed(2)}V)`);
else if (voltage > 5.5)      reasons.push(`Overvoltage (${voltage.toFixed(2)}V)`);
if (current > 2.0)           reasons.push(`Overcurrent (${current.toFixed(3)}A)`);
const gyroMag = Math.sqrt(gyro_x**2 + gyro_y**2 + gyro_z**2);
if (gyroMag > 250)           reasons.push(`High angular rate (${gyroMag.toFixed(1)} deg/s)`);

const deviceFlagged  = body.is_anomaly === true || body.is_anomaly === 'true';
const is_anomaly     = deviceFlagged || reasons.length > 0;
const anomaly_reason = is_anomaly
  ? (body.anomaly_reason || reasons.join('; ') || 'Flagged by device')
  : null;

return [{
  json: {
    device_id,
    temperature,
    voltage,
    current,
    gyro_x,
    gyro_y,
    gyro_z,
    is_anomaly,
    anomaly_reason,
    _raw_body: body
  }
}];

// ── Claude workflow health audit ─────────────────────────────────────────
// Called on EVERY execution (both anomaly and normal).
// Sends last 10 executions summary to Claude to check:
//  1. Are nodes firing in correct order?
//  2. Are any nodes erroring silently?
//  3. Is the anomaly detection logic producing expected results?
//  4. Are Supabase inserts succeeding?
// Claude responds with: { healthy: bool, issues: [], suggestion: string }

const ANTHROPIC_API_KEY = $env.ANTHROPIC_API_KEY;
if (!ANTHROPIC_API_KEY) {
  return [{ json: { healthy: true, issues: [], suggestion: 'ANTHROPIC_API_KEY not set — skipping audit.' } }];
}

const validated = $('Validate & Detect Anomaly').item.json;
const insertStatus = (() => {
  try { return $('Insert to Supabase').item.json; }
  catch { return { error: 'Insert node not yet executed' }; }
})();

// Build a workflow execution snapshot for Claude to audit
const snapshot = {
  execution_time: new Date().toISOString(),
  nodes_executed: [
    { name: 'Webhook',                  status: 'ok' },
    { name: 'Validate & Detect Anomaly', status: 'ok', output: validated },
    { name: 'Insert to Supabase',       status: insertStatus.error ? 'error' : 'ok', output: insertStatus }
  ],
  payload_received: {
    device_id:    validated.device_id,
    temperature:  validated.temperature,
    voltage:      validated.voltage,
    current:      validated.current,
    gyro_x:       validated.gyro_x,
    gyro_y:       validated.gyro_y,
    gyro_z:       validated.gyro_z,
    is_anomaly:   validated.is_anomaly,
    anomaly_reason: validated.anomaly_reason
  },
  anomaly_thresholds: {
    temperature_warn: 70, temperature_crit: 85,
    voltage_low: 3.0, voltage_high: 5.5,
    current_max: 2.0, gyro_max_dps: 250
  },
  expected_flow: [
    'Webhook → Validate & Detect Anomaly → Insert to Supabase → Is Anomaly? → (anomaly branch OR nominal branch) → Respond 201'
  ]
};

const prompt = `You are an n8n workflow quality auditor for the AegisSpace telemetry pipeline.

Review this single execution snapshot and check:
1. Did all nodes execute in the correct order?
2. Are the sensor values within plausible physical ranges?
3. Is the anomaly detection firing correctly based on the thresholds?
4. Did the Supabase insert succeed (no error field)?
5. Is anything unexpected or suspicious?

Execution snapshot:
${JSON.stringify(snapshot, null, 2)}

Respond ONLY with valid JSON. No markdown:
{
  "healthy": true | false,
  "issues": ["<issue1>", "<issue2>"],
  "suggestion": "<one actionable improvement or 'No issues found'>"
}`;

const response = await fetch('https://api.anthropic.com/v1/messages', {
  method: 'POST',
  headers: {
    'x-api-key':         ANTHROPIC_API_KEY,
    'anthropic-version': '2023-06-01',
    'content-type':      'application/json'
  },
  body: JSON.stringify({
    model:      'claude-sonnet-4-6',
    max_tokens: 256,
    system:     'You are a workflow auditor AI. Always respond with valid JSON only. No markdown.',
    messages:   [{ role: 'user', content: prompt }]
  })
});

if (!response.ok) {
  console.warn(`Claude audit failed: ${response.status}`);
  return [{ json: { healthy: true, issues: [], suggestion: `Audit unavailable (${response.status})` } }];
}

const result = await response.json();
const text   = result.content?.[0]?.text ?? '{}';
const clean  = text.replace(/```(?:json)?/g, '').trim();
const match  = clean.match(/\{[\s\S]*\}/);

let audit = { healthy: true, issues: [], suggestion: 'No issues found' };
if (match) {
  try { audit = JSON.parse(match[0]); } catch {}
}

// Log non-healthy audits prominently
if (!audit.healthy) {
  console.warn('[CLAUDE AUDIT] Issues detected:', JSON.stringify(audit.issues));
  console.warn('[CLAUDE AUDIT] Suggestion:', audit.suggestion);
} else {
  console.log('[CLAUDE AUDIT] Healthy. Suggestion:', audit.suggestion);
}

return [{ json: audit }];

// Log anomaly for audit trail
// Extend this node to add: Slack, email, PagerDuty, etc.
const d = $('Validate & Detect Anomaly').item.json;
const audit = $('Claude Workflow Audit').item.json;
console.log(`[ANOMALY] device=${d.device_id} reason="${d.anomaly_reason}" temp=${d.temperature} V=${d.voltage}`);
console.log(`[AUDIT]   healthy=${audit.healthy} suggestion="${audit.suggestion}"`);
return [{ json: { logged: true, device_id: d.device_id, reason: d.anomaly_reason, audit } }];
